export default function createLruCache(maxSize) {
  if (!Number.isFinite(maxSize) || maxSize % 1 !== 0 || maxSize <= 0) {
    throw new TypeError('maxSize must be a positive integer');
  }

  const map = new Map();

  const touch = (key, value) => {
    map.delete(key);
    map.set(key, value);
  };

  const evictIfNeeded = () => {
    while (map.size > maxSize) {
      const oldest = map.keys().next().value;
      map.delete(oldest);
    }
  };

  return {
    get(key) {
      if (!map.has(key)) return undefined;
      const value = map.get(key);
      touch(key, value);
      return value;
    },
    set(key, value) {
      touch(key, value);
      evictIfNeeded();
    },
    has(key) {
      return map.has(key);
    },
    size() {
      return map.size;
    },
    clear() {
      map.clear();
    },
    keys() {
      return Array.from(map.keys());
    }
  };
}
